import React, { useState, useEffect } from "react";
import io from "socket.io-client";

function App() {
  const [socket, setSocket] = useState(null);
  const [username, setUsername] = useState("");
  const [room, setRoom] = useState("");
  const [message, setMessage] = useState("");
  const [messageList, setMessageList] = useState([]);
  const [showChat, setShowChat] = useState(false);

  useEffect(() => {
    const newSocket = io("http://localhost:5000");
    setSocket(newSocket);
    return () => newSocket.close();
  }, []);

  const joinRoom = () => {
    if (username && room && socket) {
      setMessageList([]);
      socket.emit("join_room", room);
      setShowChat(true);
    }
  };

  const sendMessage = () => {
    if (message !== "" && socket) {
      const messageData = {
        room,
        author: username,
        message,
        time: new Date().toLocaleTimeString(),
      };

      socket.emit("send_message", messageData);
      setMessage("");
    }
  };

  useEffect(() => {
    if (!socket) return;

    const loadHandler = (data) => setMessageList(data);
    const messageHandler = (data) =>
      setMessageList((list) => [...list, data]);

    socket.on("load_messages", loadHandler);
    socket.on("receive_message", messageHandler);

    return () => {
      socket.off("load_messages", loadHandler);
      socket.off("receive_message", messageHandler);
    };
  }, [socket]);

  return (
    <div className="h-screen flex items-center justify-center bg-gray-900">
      {!showChat ? (
        <div className="bg-white p-8 rounded-xl shadow-lg w-80">
          <h2 className="text-2xl font-bold mb-4 text-center">
            Join Chat 💬
          </h2>

          <input
            className="w-full mb-3 p-2 border rounded"
            placeholder="Username"
            onChange={(e) => setUsername(e.target.value)}
          />

          <input
            className="w-full mb-3 p-2 border rounded"
            placeholder="Room ID"
            onChange={(e) => setRoom(e.target.value)}
          />

          <button
            className="w-full bg-blue-500 text-white p-2 rounded hover:bg-blue-600"
            onClick={joinRoom}
          >
            Join
          </button>
        </div>
      ) : (
        <div className="w-96 bg-white rounded-xl shadow-lg flex flex-col h-[500px]">

          {/* Header */}
          <div className="bg-blue-500 text-white p-3 text-center font-bold rounded-t-xl">
            Room: {room}
          </div>

          {/* Messages */}
          <div className="flex-1 p-3 overflow-y-auto bg-gray-100">
            {messageList.map((msg, index) => (
              <div
                key={index}
                className={`flex ${
                  msg.author === username ? "justify-end" : "justify-start"
                } mb-2`}
              >
                <div
                  className={`p-2 rounded-lg max-w-[70%] ${
                    msg.author === username
                      ? "bg-green-500 text-white"
                      : "bg-gray-300"
                  }`}
                >
                  <div className="text-sm font-semibold">{msg.author}</div>
                  <div>{msg.message}</div>
                  <div className="text-[10px] text-right">
                    {msg.time}
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Input */}
          <div className="flex p-2 border-t">
            <input
              className="flex-1 p-2 border rounded mr-2"
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Type message..."
            />
            <button
              className="bg-blue-500 text-white px-4 rounded"
              onClick={sendMessage}
            >
              Send
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
